/* Binary search the ascending code-point table. Returns glyph index or -1. */
static inline int cjk_lookup(uint32_t cp) {
    int lo = 0, hi = CJK_GLYPH_COUNT - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        uint32_t v = cjk_codepoints[mid];
        if (v == cp) return mid;
        if (v < cp) lo = mid + 1; else hi = mid - 1;
    }
    return -1;
}

